								? "repository could not be inferred from origin remote"
								: null,
				};

	const projectListing =
		remote?.owner && ghAvailability.available && ghAuth.ok
			? readProjectListing(remote.owner)
			: {
					available: false,
					summary: !ghAvailability.available
						? "gh is not available"
