	return spawnSync(command, args, {
		encoding: "utf8",
		timeout,
	});
}

function runGhGraphQL(query: string, variables: Record<string, unknown>) {
	const variableArgs = Object.entries(variables).flatMap(([key, value]) => [
		"-F",
		`${key}=${typeof value === "string" ? value : String(value)}`,
	]);
	const result = run(
		"gh",
		[
			"api",
			"graphql",
			"-F",
			`query=${query}`,
			...variableArgs,
		],
		15_000,
	);

	if (result.status !== 0) {
		return {
			ok: false,
			errorSummary: summarizeAuthResult(result),
			data: null as unknown,
		};
	}

	try {
		return {
			ok: true,
			errorSummary: null as string | null,
			data: JSON.parse(result.stdout) as unknown,
		};
